module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output wire [15:0] result,
    output wire [15:0] odd
);

reg [15:0] result_reg;
reg [15:0] odd_reg;

always @(*) begin
    if (B == 0) begin
        result_reg = 16'b0;
        odd_reg = A;
    end
    else begin
        {result_reg, odd_reg} = {16'b0, A};
        while (odd_reg >= B) begin
            odd_reg = odd_reg - B;
            result_reg = result_reg + 16'h0001;
        end
    end
end

assign result = result_reg;
assign odd = odd_reg;

endmodule
